const incoming = $input.first()?.json || {};
const payload = incoming.body && typeof incoming.body === 'object' ? incoming.body : incoming;

function normalizeMetricList(raw) {
  return [...new Set(String(raw || '')
    .split(',')
    .map((value) => value.trim().toLowerCase())
    .filter(Boolean))];
}

function readValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') return value;
  }
  return '';
}

const startDate = String(readValue(payload['✅START_DATE'], payload.startDate, $today.toFormat('yyyy-MM-dd')));
const endDate = String(readValue(payload['✅END_DATE'], payload.endDate, startDate));
const includeList = String(readValue(payload.INCLUDE_LIST, payload.includeList, ''));
const selectedMetrics = normalizeMetricList(includeList);
const dryRun = payload.DRY_RUN ?? payload.dryRun ?? true;

const auth = {
  amazon: {
    accessToken: readValue(payload.auth?.amazon?.accessToken, payload.AMAZON_ACCESS_TOKEN),
    clientId: readValue(payload.auth?.amazon?.clientId, payload.AMAZON_ADS_CLIENT_ID),
    profileId: readValue(payload.auth?.amazon?.profileId, payload.AMAZON_ADS_PROFILE_ID),
  },
  google: {
    accessToken: readValue(payload.auth?.google?.accessToken, payload.GOOGLE_ACCESS_TOKEN),
  },
};

return [{
  json: {
    ...payload,
    '✅START_DATE': startDate,
    '✅END_DATE': endDate,
    INCLUDE_LIST: includeList,
    selectedMetrics,
    runAll: selectedMetrics.length === 0,
    dryRun: Boolean(dryRun),
    auth,
    triggeredVia: incoming.body ? 'webhook' : 'manual',
  },
}];

const payload = $input.first().json || {};
const context = payload.orchestrator || {};
const status = payload.shouldRun ? 'dry_run' : 'skipped';
return {
  json: {
    metricKey: context.metricKey,
    displayName: context.displayName,
    workflowId: context.workflowId,
    dateMode: context.dateMode,
    selected: Boolean(payload.shouldRun),
    status,
    errorMessage: null,
    startedAt: payload.shouldRun ? context.startedAt || null : null,
    finishedAt: new Date().toISOString(),
    order: context.index ?? 0,
  },
};

const payload = $input.first().json || {};
const context = payload.orchestrator || {};
const error = payload.error || payload.execution?.error || null;
return {
  json: {
    metricKey: context.metricKey,
    displayName: context.displayName,
    workflowId: context.workflowId,
    dateMode: context.dateMode,
    selected: true,
    status: error ? 'failed' : 'success',
    errorMessage: error ? String(error.message || payload.message || 'Child workflow failed') : null,
    startedAt: context.startedAt || null,
    finishedAt: new Date().toISOString(),
    order: context.index ?? 0,
  },
};

const summary = $input.all().map((item) => item.json).sort((a, b) => Number(a.order || 0) - Number(b.order || 0));
const totals = summary.reduce((acc, item) => {
  acc.total += 1;
  acc[item.status] = (acc[item.status] || 0) + 1;
  return acc;
}, { total: 0, success: 0, failed: 0, skipped: 0, dry_run: 0 });
return [{ json: { totals, summary } }];
